let lastTime = 0;
let playerPosition = [0, 0];
let speed = 1;

function validateInput(input) {
    if (typeof input !== 'number' || isNaN(input)) {
        throw new Error('Invalid input');
    }
}

function update(deltaTime) {
    const currentTime = performance.now();
    const timeElapsed = deltaTime;
    const distanceTraveled = speed * timeElapsed / 1000;

    playerPosition[0] += Math.cos(playerPosition[1]) * distanceTraveled;
    playerPosition[1] += Math.sin(playerPosition[1]) * distanceTraveled;

    lastTime = currentTime;
}

function draw() {
    const canvas = document.getElementById('canvas');
    const ctx = canvas.getContext('2d');

    ctx.clearRect(0, 0, canvas.width, canvas.height);
    ctx.beginPath();
    ctx.arc(playerPosition[0], playerPosition[1], 10, 0, 2 * Math.PI);
    ctx.fillStyle = 'red';
    ctx.fill();

    const distanceText = document.getElementById('distance');
    distanceText.textContent = `Distance: ${Math.round(playerPosition[0])}m`;
}

function gameLoop() {
    try {
        validateInput(speed);

        const currentTime = performance.now();
        const deltaTime = (currentTime - lastTime) / 1000;

        update(deltaTime);
        draw();

        requestAnimationFrame(gameLoop);
    } catch (error) {
        console.error(error);
    }
}

document.addEventListener('DOMContentLoaded', () => {
    gameLoop();
});